%% Evaluate convergence study of geometrically exact beam models
% For convergence in both space and time
% Requires the data generated by the corresponding simulation scripts.
%
% Maximilian Herrmann
% Chair of Automatic Control
% TUM School of Engineering and Design
% Technical University of Munich
%

%% Preparation

%#ok<*UNRCH>

clear
close all

% Disable warnings for extra legend entries
warning('off', 'MATLAB:legend:IgnoringExtraEntries');


%% Script Settings

SAVE_PLOTS = 0;

PLOT_SUBFOLDER = 'evaluations';

PLOT_FOLDER = fullfile(getRootFolder, "results", "plots");

% Path to results folder
RESULTS_DIR = fullfile(getRootFolder, "results", "runs");

% Simulation run to load (in RESULTS_DIR)
SIM_SUBFOLDER = '240805_1329_simResults_convSpace';


%% Load results

% Load simCase struct
disp('Loading simulation results file...')
resultsPath = fullfile(RESULTS_DIR, SIM_SUBFOLDER);
results = load( fullfile( resultsPath, 'convStudyResults.mat') );

beamPars = results.beamPars;
h = results.h;
nSeg = results.nSeg;

simErrors    = results.simErrors;
simTimeTotal = results.simTimeTotal;

%modelNames = [results.beamModels.modelName];

% %% TEMP 29.07.24: Copy data for correct dimensions
% if size(results.simErrors,4) == 1 && size(results.simErrors,5) == 1
%     simErrors    = zeros(1,length(h),length(nSeg),5,2);
%     simTimeTotal = zeros(1,length(h),length(nSeg),5,2);
% 
%     for iMdl = 1:5
%         for iRefMdl = 1:2
%             simErrors(1,:,1,iMdl,iRefMdl) = results.simErrors;
%             simTimeTotal(1,:,1,iMdl,iRefMdl) = results.simTimeTotal;
%         end
%     end
% 
%     modelNames = string(1:5);
% end

%% Add mixed simError to results array
% Simulation error of all models with respect to the respective model types
% i.e.: 6-Dof SR models -- absolute reference simulation with 6 DoF / SR
% (absKin LGVI); relative reduced model: Relative reduced reference
% simulation

%%% Note: The assignment here must correspond specifically to the models
%%% defiend in the simulation script!

% The reference simulation type is stored in the last dimension:
% (E, h, nSeg, integrator, refMdl)

if size(simErrors,5) > 1
    % Copy absKin LGVI error
    simErrors(:,:,:,:,3) = simErrors(:,:,:,:,1);

    % Use relKinRed error for relKinRed Models
    simErrors(:,:,:,3,3)   = simErrors(:,:,:,3,2);
    simErrors(:,:,:,5,3)   = simErrors(:,:,:,5,2);
end

% Names for the simulation error types
simErrorNamesLong = [
    "Relative Simulation Error (Absolute Model SR)";
    "Relative Simulation Error (Relative Model KH)";
    "Relative Simulation Error (Individual Ref.)"
    ];
simErrorNamesShort = [
    "Sim Error Abs Full";
    "Sim Error Rel Red";
    "Sim Error Indiv."
    ];


%% Temp: Permute integrators

permuteVec = [1, 2, 4, 3, 5];
simErrors      = simErrors(:,:,:,permuteVec,:);
simTimeTotal   = simTimeTotal (:,:,:,permuteVec,:);
modelNames = ["Abs SR", "Rel SR Broyden", "Rel SR Recursive", "Rel KH Broyden", "Rel KH Recursive"];


%% General Plot settings

% Colors and Line styles for the individual integrators
plotColors = lines(4);
plotColors = plotColors(2:end, :);
plotLines = ["-o", "-*", "-square"];
plotMarkers = ["+", "o", "square"];
plotMarkerEdgeColors = {"black", "black", "black"};

figHandles = {};


%% Metadata / Info about the parameters

% Info for first dimension / Young's modulus
dimInfo(1).legendStrings = compose("Mat=%d", 1:length(beamPars));
dimInfo(1).xAxisLabel = "Material";
dimInfo(1).xValues = beamPars;
dimInfo(1).quantNameLong = "Material";
dimInfo(1).quantNameShort = "Mat";

% Info for 2nd dimension / time step
dimInfo(2).legendStrings = compose("h=%.2E", h);
dimInfo(2).xAxisLabel = "time step $h$ / s";
dimInfo(2).xValues = h;
dimInfo(2).quantNameLong = "Time Step $h$";
dimInfo(2).quantNameShort = "h";

% Info for 3rd dimension / nr. of segments
dimInfo(3).legendStrings = compose("nSeg=%d", nSeg);
dimInfo(3).xAxisLabel = "$n^{-1}$";
dimInfo(3).xValues = 1./nSeg;
dimInfo(3).quantNameLong = "Nr. of Segments";
dimInfo(3).quantNameShort = "nSeg";

% Info for 4th dimension / integrator model
% (will not be used as x axis values)
dimInfo(4).legendStrings = modelNames;
dimInfo(4).xAxisLabel = "";
dimInfo(4).xValues = 1:length(modelNames);
dimInfo(4).quantNameLong = "";
dimInfo(4).quantNameShort = "ints.";


%% Plot results

convTime(size(simErrors, 5))  = struct("a", [], "b", [], "rsquare", []);
convSpace(size(simErrors, 5)) = struct("a", [], "b", [], "rsquare", []);

for iSimError = 1:size(simErrors, 5)

    disp('Estimating Convergence Rates...')
    [convTime(iSimError), convSpace(iSimError)] = estimateConvRates(simErrors(:,:,:,:,iSimError), beamPars, h, nSeg, modelNames);


    disp('Generating Plots...')


    % Surf plot with separate plots in E
    opts = struct( ...
        "figureName",       "Sim Error Abs / h & nSeg", ...
        "figureTitle",      strcat(simErrorNamesLong(iSimError), " over $h$ and nSeg"), ...
        "axisLabel",        "relative error $\epsilon_\mathrm{rel}$" ...
        );

    figHandles{end+1} = plotQuantitySurf(simErrors(:,:,:,:,iSimError), beamPars, h, nSeg, modelNames, opts);

    % Separate 2D plots
    figInfo = struct( ...
        "quantNameShort", simErrorNamesShort(iSimError), ...
        "quantNameLong",  simErrorNamesLong(iSimError), ...
        "yAxisLabel",     "relative error $\epsilon_\mathrm{rel}$" ...
        );

    figHandles{end+1} = plotQuantity2d(simErrors(:,:,:,:,iSimError), dimInfo, figInfo, convTime(iSimError), convSpace(iSimError));

end


%% Generate Paper Plots
fh_mbsd = gobjects(0);

% Global plot settings
lineWidth = 1.2;
markerSize = 7;
lineStyles = ["-square", "-o", "-*", "-o", "-*"];
lineColors = [
    tumColors().TUMBlue;
    tumColors().TUMOrange;
    tumColors().TUMOrange;
    tumColors().TUMGreen;
    tumColors().TUMGreen;
    ];

pdfWidth = 430/2; % Page width in pt
pdfAspectRatio = 1.5;

if contains(SIM_SUBFOLDER, "Time")


    %%% Individual errors

    fh_mbsd(end+1) = figure("Name", "simError_time_indiv");
    axTime = axes(fh_mbsd(end));


    % Plot comparison line
    b = 2; % Desired exponent
    p = ( simErrors(1,4,1,1,3) + 1e-8); % Desired point on the line
    a =  p / (h(end-1)^b ); % Compute factor a
    convLine = @(x) a*x.^b;
    plot(axTime, ...
        h, convLine(h), ...
        '--', ...
        'Color', "black", ...
        'DisplayName', sprintf('$%.5g \\, h^{%.3g}$', a, b) ...
        );
    hold on;

    % Plot errors
    for iLine = 1:size(simErrors, 4)
        plot(axTime, ...
            h, squeeze(simErrors(:,:,:,iLine,3)), ...
            lineStyles(iLine), ...
            'Color', lineColors(iLine, :), 'MarkerSize', markerSize, ...
            'LineWidth', lineWidth, ...
            ...%'MarkerFaceColor', opts.plotColors(iSim, :), 'MarkerEdgeColor', opts.plotMarkerEdgeColors{iSim},...
            'DisplayName', modelNames(iLine) ...
            );
        hold on;
    end
    axTime.XScale = 'log';
    axTime.YScale = 'log';
    %axTime.XLim = sort(h([1,end]));
    xlabel("$h$ in s", 'Interpreter','latex');
    ylabel("$\epsilon_\mathrm{rel}$", 'Interpreter', 'latex');
    %xticks(sort(h));
    %xticklabels(arrayfun(@(x) sprintf("$2^{%d}$", x), log2(flip(h))));
    %xticks([1e-6, 5e-6, 1e-5]);
    %xticklabels(["10^-6", "5 \cdot 10^-6"]);
    axTime.TickLabelInterpreter = "latex";
    grid on;
    lgnd = legend("Interpreter", "latex", "Location","northwest");
    % Transparent background
    % https://www.mathworks.com/matlabcentral/answers/97850-how-do-i-make-the-background-of-a-plot-legend-transparent#comment_847440
    lgnd.BoxFace.ColorType='truecoloralpha';
    lgnd.BoxFace.ColorData=uint8(255*[1 1 1 0.75]');

    formatAndSaveFigureFixedWidth(fh_mbsd(end), pdfWidth, pdfAspectRatio, PLOT_FOLDER);



    %%% Absolute Error
    fh_mbsd(end+1) = figure("Name", "simError_time_abs");
    axTime = axes(fh_mbsd(end));


    % Plot comparison line
    b = 2; % Desired exponent
    p = ( simErrors(1,end-1,1,1,1) + 1e-8); % Desired point on the line
    a =  p / (h(end-1)^b ); % Compute factor a
    convLine = @(x) a*x.^b;
    plot(axTime, ...
        h, convLine(h), ...
        '--', ...
        'Color', "black", ...
        'DisplayName', sprintf('$%.5g \\, h^{%.3g}$', a, b) ...
        );
    hold on;

    % Plot errors
    for iLine = 1:size(simErrors, 4)
        plot(axTime, ...
            h, squeeze(simErrors(:,:,:,iLine,1)), ...
            lineStyles(iLine), ...
            'Color', lineColors(iLine, :), 'MarkerSize', markerSize, ...
            'LineWidth', lineWidth, ...
            ...%'MarkerFaceColor', opts.plotColors(iSim, :), 'MarkerEdgeColor', opts.plotMarkerEdgeColors{iSim},...
            'DisplayName', modelNames(iLine) ...
            );
        hold on;
    end
    axTime.XScale = 'log';
    axTime.YScale = 'log';
    %axTime.XLim = sort(h([1,end]));
    xlabel("$h$ in s", 'Interpreter','latex');
    ylabel("$\epsilon_\mathrm{rel}$", 'Interpreter', 'latex');
    %xticks(sort(h));
    %xticklabels(arrayfun(@(x) sprintf("$2^{%d}$", x), log2(flip(h))));
    %xticks([1e-6, 5e-6, 1e-5]);
    %xticklabels(["10^-6", "5 \cdot 10^-6"]);
    axTime.TickLabelInterpreter = "latex";
    grid on;
    %legend("Interpreter", "latex", "Location","northwest");

    lgnd = legend("Interpreter", "latex", "Location","northwest");
    % Transparent background
    % https://www.mathworks.com/matlabcentral/answers/97850-how-do-i-make-the-background-of-a-plot-legend-transparent#comment_847440
    lgnd.BoxFace.ColorType='truecoloralpha';
    lgnd.BoxFace.ColorData=uint8(255*[1 1 1 0.75]');


    formatAndSaveFigureFixedWidth(fh_mbsd(end), pdfWidth, pdfAspectRatio, PLOT_FOLDER);


end



if contains(SIM_SUBFOLDER, "Space")

    %%% Individual errors

    fh_mbsd(end+1) = figure("Name", "simError_space_indiv");
    axSpace = axes(fh_mbsd(end));


    % Plot comparison line
    b = 2; % Desired exponent
    p = ( simErrors(1,1,1,1,3) + 5e-3); % Desired point on the line
    a =  p / (1./nSeg(1)^b ); % Compute factor a
    convLine = @(x) a*x.^b;
    plot(axSpace, ...
        1./nSeg, convLine(1./nSeg), ...
        '--', ...
        'Color', "black", ...
        'DisplayName', sprintf('$%.3g \\, l^{%.3g}$', a, b) ...
        );
    hold on;

    % Plot errors
    for iLine = 1:size(simErrors, 4)
        plot(axSpace, ...
            1./nSeg, squeeze(simErrors(:,:,:,iLine,3)), ...
            lineStyles(iLine), ...
            'Color', lineColors(iLine, :), 'MarkerSize', markerSize, ...
            'LineWidth', lineWidth, ...
            ...%'MarkerFaceColor', opts.plotColors(iSim, :), 'MarkerEdgeColor', opts.plotMarkerEdgeColors{iSim},...
            'DisplayName', modelNames(iLine) ...
            );
        hold on;
    end
    axSpace.XScale = 'log';
    axSpace.YScale = 'log';
    axSpace.XLim = sort(1./nSeg([1,end]));
    xlabel("$l$ in m", 'Interpreter','latex');
    ylabel("$\epsilon_\mathrm{rel}$", 'Interpreter', 'latex');
    xticks(sort(1./nSeg));
    xticklabels(arrayfun(@(x) sprintf("$1/%d$", x), flip(nSeg)));
    axSpace.TickLabelInterpreter = "latex";
    grid on;
    lgnd = legend("Interpreter", "latex", "Location","northwest");
    % Transparent background
    % https://www.mathworks.com/matlabcentral/answers/97850-how-do-i-make-the-background-of-a-plot-legend-transparent#comment_847440
    lgnd.BoxFace.ColorType='truecoloralpha';
    lgnd.BoxFace.ColorData=uint8(255*[1 1 1 0.75]');


    formatAndSaveFigureFixedWidth(fh_mbsd(end), pdfWidth, pdfAspectRatio, PLOT_FOLDER);



    %%% Absolute Error
    fh_mbsd(end+1) = figure("Name", "simError_space_abs");
    axSpace = axes(fh_mbsd(end));


    % Plot comparison line
    b = 2; % Desired exponent
    p = ( simErrors(1,1,1,1,1) + 7e-3); % Desired point on the line
    a =  p / (1./nSeg(1)^b ); % Compute factor a
    convLine = @(x) a*x.^b;
    plot(axSpace, ...
        1./nSeg, convLine(1./nSeg), ...
        '--', ...
        'Color', "black", ...
        'DisplayName', sprintf('$%.3g \\, l^{%.3g}$', a, b) ...
        );
    hold on;

    % Plot errors
    for iLine = 1:size(simErrors, 4)
        plot(axSpace, ...
            1./nSeg, squeeze(simErrors(:,:,:,iLine,1)), ...
            lineStyles(iLine), ...
            'Color', lineColors(iLine, :), 'MarkerSize', markerSize, ...
            'LineWidth', lineWidth, ...
            ...%'MarkerFaceColor', opts.plotColors(iSim, :), 'MarkerEdgeColor', opts.plotMarkerEdgeColors{iSim},...
            'DisplayName', modelNames(iLine) ...
            );
        hold on;
    end
    axSpace.XScale = 'log';
    axSpace.YScale = 'log';
    axSpace.XLim = sort(1./nSeg([1,end]));
    xlabel("$l$ in m", 'Interpreter','latex');
    ylabel("$\epsilon_\mathrm{rel}$", 'Interpreter', 'latex');
    xticks(sort(1./nSeg));
    xticklabels(arrayfun(@(x) sprintf("$1/%d$", x), flip(nSeg)));
    axSpace.TickLabelInterpreter = "latex";
    grid on;
    legend("Interpreter", "latex", "Location","northwest");

    formatAndSaveFigureFixedWidth(fh_mbsd(end), pdfWidth, pdfAspectRatio, PLOT_FOLDER);

end







%% Save Plots

figHandlesVec = [figHandles{:}];

if SAVE_PLOTS
    disp('Saving Plots...')

    saveDirPlots = fullfile( resultsPath, PLOT_SUBFOLDER );

    % Create output folder
    if ~isfolder( saveDirPlots )
        mkdir( saveDirPlots );
    end

    % Case Plots
    for iPlot = 1:length(figHandlesVec)

        % Replace '/' in figure names
        figName = replace( figHandlesVec(iPlot).Name, '/', '--');

        filePath = fullfile( resultsPath, PLOT_SUBFOLDER, figName );

        % Save as figure
        savefig( ...
            figHandlesVec(iPlot), ...
            sprintf('%s.fig', filePath), ...
            'compact' );

        % Save as jpeg
        exportgraphics( ...
            figHandlesVec(iPlot), ...
            sprintf('%s.jpeg', filePath));
    end
end

disp('Finished.');


